#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N;
        scanf("%d %d", &M, &N);
        long long A[M], B[M], result = 0;
        for (int i = 0; i < M; i++) scanf("%lld", &A[i]);
        for (int i = 0; i < M; i++) scanf("%lld", &B[i]);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < M; j++) {
                long long fib[N + 1];
                fib[1] = A[i];
                fib[2] = B[j];
                for (int k = 3; k <= N; k++) {
                    fib[k] = (fib[k - 1] + fib[k - 2]) % MOD;
                }
                result = (result + fib[N]) % MOD;
            }
        }
        printf("%lld\n", result);
    }
    return 0;
}

