import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int M = sc.nextInt();
            int N = sc.nextInt();
            long[] A = new long[M];
            long[] B = new long[M];
            for (int i = 0; i < M; i++) A[i] = sc.nextLong();
            for (int i = 0; i < M; i++) B[i] = sc.nextLong();
            long result = 0;
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < M; j++) {
                    long[] fib = new long[N + 1];
                    fib[1] = A[i];
                    fib[2] = B[j];
                    for (int k = 3; k <= N; k++) {
                        fib[k] = (fib[k - 1] + fib[k - 2]) % 1000000007;
                    }
                    result = (result + fib[N]) % 1000000007;
                }
            }
            System.out.println(result);
        }
    }
}

